svg.script:
(function(){
var root=document.documentElement;
function q(sel){return Array.prototype.slice.call(root.querySelectorAll(sel));}
function toPoint(evt){var pt=root.createSVGPoint();pt.x=evt.clientX;pt.y=evt.clientY;return pt.matrixTransform(root.getScreenCTM().inverse());}
q('[data-draggable="legend"]').forEach(function(legend){
 var draggingLegend=false, legendDx=0, legendDy=0;
 function legendX(){return parseFloat(legend.getAttribute('data-x')||'0');}
 function legendY(){return parseFloat(legend.getAttribute('data-y')||'0');}
 function setLegend(x,y){legend.setAttribute('data-x',x);legend.setAttribute('data-y',y);legend.setAttribute('transform','translate('+x+' '+y+')');}
 function startLegendDrag(evt){var p=toPoint(evt);draggingLegend=true;legendDx=p.x-legendX();legendDy=p.y-legendY();legend.setAttribute('class','trace-legend-wrap dragging');evt.preventDefault();}
 function moveLegendDrag(evt){if(!draggingLegend) return;var p=toPoint(evt);setLegend(p.x-legendDx,p.y-legendDy);evt.preventDefault();}
 function endLegendDrag(){draggingLegend=false;legend.setAttribute('class','trace-legend-wrap');}
 legend.addEventListener('pointerdown',startLegendDrag);
 root.addEventListener('pointermove',moveLegendDrag);
 root.addEventListener('pointerup',endLegendDrag);
 root.addEventListener('pointerleave',endLegendDrag);
});
})();
